#define EW(sym, n) ASM_GSYM(sym) ".skip (" #n ")*2\n" /* resw: n words  */
#define EALIAS(sym) ASM_GSYM(sym) /* zero-size alias */

/* .data fills */
#define FILLB(sym, count, val) ASM_GSYM(sym) ".fill " #count ",1," #val "\n"

